# Problem: Detect and fix the N+1 query problem in ORM-based applications.
# The N+1 problem occurs when fetching N parent records triggers N additional
# queries to load related children, instead of using efficient batch loading.
#
# Approach:
# - Build a QueryTracker context manager using sqlite3's set_trace_callback
#   to count every SQL statement executed within a block.
# - Implement a MiniORM with authors/books tables and per-author book lookups.
# - Show three loading strategies: naive (N+1), JOIN-based (1 query),
#   and subquery-based (2 queries), then detect which is N+1.
#
# Time complexity: O(N*M) for naive (N authors, M avg books), O(N+M) for eager.
# Space complexity: O(N+M) for all approaches (storing all results).
#
# Key steps:
# 1. QueryTracker installs a trace callback that increments a counter per query.
# 2. MiniORM provides CRUD for authors and books with parameterized queries.
# 3. naive_author_books demonstrates N+1 by looping get_books_by_author.
# 4. eager_join_author_books uses a single LEFT JOIN query, groups in Python.
# 5. eager_subquery_author_books uses 2 queries: all authors + books WHERE IN.
# 6. detect_n_plus_one wraps any strategy in QueryTracker and checks the count.

import sqlite3
from collections import defaultdict


class QueryTracker:

    def __init__(self, conn: sqlite3.Connection):
        self.conn = conn
        self._count = 0

    def _trace(self, statement):
        self._count += 1

    def __enter__(self):
        self._count = 0
        self.conn.set_trace_callback(self._trace)
        return self

    def __exit__(self, *args):
        self.conn.set_trace_callback(None)

    @property
    def query_count(self) -> int:
        return self._count


class MiniORM:

    def __init__(self, conn: sqlite3.Connection):
        self.conn = conn
        self.conn.execute(
        )
        self.conn.execute(
        )
        self.conn.commit()

    def add_author(self, name: str) -> int:
        cursor = self.conn.execute("INSERT INTO authors (name) VALUES (?)", (name,))
        self.conn.commit()
        return cursor.lastrowid

    def add_book(self, title: str, author_id: int) -> int:
        cursor = self.conn.execute(
            "INSERT INTO books (title, author_id) VALUES (?, ?)", (title, author_id)
        )
        self.conn.commit()
        return cursor.lastrowid

    def get_all_authors(self) -> list[dict]:
        cursor = self.conn.execute("SELECT id, name FROM authors ORDER BY name")
        return [{"id": row[0], "name": row[1]} for row in cursor.fetchall()]

    def get_books_by_author(self, author_id: int) -> list[dict]:
        cursor = self.conn.execute(
            "SELECT id, title, author_id FROM books WHERE author_id = ?", (author_id,)
        )
        return [{"id": row[0], "title": row[1], "author_id": row[2]} for row in cursor.fetchall()]


def naive_author_books(orm: MiniORM) -> list[dict]:
    authors = orm.get_all_authors()  # 1 query
    result = []
    for author in authors:  # N queries (one per author)
        books = orm.get_books_by_author(author["id"])
        result.append({
            "author": author["name"],
            "books": [b["title"] for b in books],
        })
    # Already sorted by name since get_all_authors orders by name
    return result


def eager_join_author_books(orm: MiniORM) -> list[dict]:
    cursor = orm.conn.execute(
    )
    # Group results by author, preserving order
    grouped = defaultdict(list)
    author_names = {}  # id -> name, to preserve insertion order
    for author_id, name, title in cursor.fetchall():
        if author_id not in author_names:
            author_names[author_id] = name
        if title is not None:  # LEFT JOIN may yield NULL for authors with no books
            grouped[author_id].append(title)
    return [
        {"author": author_names[aid], "books": grouped[aid]}
        for aid in author_names
    ]


def eager_subquery_author_books(orm: MiniORM) -> list[dict]:
    # Query 1: all authors
    author_cursor = orm.conn.execute("SELECT id, name FROM authors ORDER BY name")
    authors = author_cursor.fetchall()

    author_ids = [a[0] for a in authors]
    books_by_author = defaultdict(list)

    if author_ids:
        # Query 2: all books for these authors in one shot
        placeholders = ",".join("?" for _ in author_ids)
        book_cursor = orm.conn.execute(
            f"SELECT title, author_id FROM books WHERE author_id IN ({placeholders})",
            author_ids,
        )
        for title, author_id in book_cursor.fetchall():
            books_by_author[author_id].append(title)

    return [
        {"author": name, "books": books_by_author[aid]}
        for aid, name in authors
    ]


def detect_n_plus_one(func, orm: MiniORM, n_authors: int) -> dict:
    with QueryTracker(orm.conn) as tracker:
        func(orm)
        count = tracker.query_count
    return {
        "query_count": count,
        "is_n_plus_one": count > n_authors,
    }
